import{_ as r,a as o}from"./chunks/Mock.BC_Zw5o6.js";import{_ as a,c as e,o as n,ah as s}from"./chunks/framework.RCw5T9E9.js";const m=JSON.parse('{"title":"Подмена трафика","description":"","frontmatter":{"title":"Подмена трафика"},"headers":[],"relativePath":"ru/network/traffic.md","filePath":"ru/network/traffic.md"}'),l={name:"ru/network/traffic.md"};function i(d,t,g,h,p,c){return n(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="breakpoints-и-mock-response" tabindex="-1">Breakpoints и Mock response <a class="header-anchor" href="#breakpoints-и-mock-response" aria-label="Permalink to &quot;Breakpoints и Mock response&quot;">​</a></h1><p>Во вкладке <strong>Network</strong> и в разделе <strong>Options → Network</strong> доступны два механизма перехвата запросов:</p><ul><li><strong>Breakpoint</strong> — остановка запроса <strong>до отправки в сеть</strong> с возможностью изменить его параметры и затем продолжить выполнение;</li><li><strong>Mock response</strong> — возврат подготовленного ответа <strong>без обращения к серверу</strong>.</li></ul><p>Оба механизма работают только для запросов, проходящих через <strong><code>fetch</code></strong> и <strong><code>XMLHttpRequest</code></strong> внутри текущей страницы.</p><p>Базовые ограничения перехвата (контекст страницы, CORS, scope перехвата и т.д.) описаны в <a href="/qa-tools/docs/ru/network/general.html">Работа с запросами</a>.</p><hr><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><p><img src="'+r+'" alt="Breakpoint"></p><h3 id="назначение" tabindex="-1">Назначение <a class="header-anchor" href="#назначение" aria-label="Permalink to &quot;Назначение&quot;">​</a></h3><p>Breakpoint позволяет остановить исходящий запрос <strong>до его отправки</strong>.</p><p>Когда URL и метод совпадают с правилом:</p><ul><li>выполнение запроса приостанавливается;</li><li>в панели становится доступно редактирование параметров;</li><li>после подтверждения запрос отправляется уже с изменениями;</li><li>либо выполнение можно отменить.</li></ul><p>Фактически перехват происходит после того, как приложение сформировало запрос, но до вызова нативной отправки.</p><h3 id="что-можно-изменить" tabindex="-1">Что можно изменить <a class="header-anchor" href="#что-можно-изменить" aria-label="Permalink to &quot;Что можно изменить&quot;">​</a></h3><p>До продолжения доступны для редактирования:</p><ul><li>HTTP-метод;</li><li>URL (схема, хост, путь, query);</li><li>заголовки;</li><li>тело запроса.</li></ul><p>После <strong>Apply</strong> запрос отправляется в сеть уже в изменённом виде.</p><h3 id="тело-запроса-raw-и-form-data-breakpoint" tabindex="-1">Тело запроса: raw и form-data (breakpoint) <a class="header-anchor" href="#тело-запроса-raw-и-form-data-breakpoint" aria-label="Permalink to &quot;Тело запроса: raw и form-data (breakpoint)&quot;">​</a></h3><p>Для остановленного запроса редактор тела можно переключить в режим <strong>Raw</strong> (одно текстовое поле) или <strong>Form-data</strong> (строки по аналогии с таблицей в детализации <strong>Network</strong>).</p><h3 id="режим-form-data" tabindex="-1">Режим Form-data <a class="header-anchor" href="#режим-form-data" aria-label="Permalink to &quot;Режим Form-data&quot;">​</a></h3><p>В режиме <strong>Form-data</strong> каждая строка содержит:</p><ul><li><strong>ключ</strong>;</li><li>тип значения (<strong>Text</strong> или <strong>File</strong>);</li><li>значение.</li></ul><p>Для строк типа <strong>File</strong> кнопка <strong>Browse</strong> позволяет выбрать файл с диска. Выбранный файл добавляется в черновик обычно как <strong>data:</strong>-URI.</p><h3 id="источники-фаилов-для-file-полеи" tabindex="-1">Источники файлов для File-полей <a class="header-anchor" href="#источники-фаилов-для-file-полеи" aria-label="Permalink to &quot;Источники файлов для File-полей&quot;">​</a></h3><p>Для строк типа <strong>File</strong> в выпадающем списке доступны:</p><ul><li><strong>оригинал</strong> — вернуть файл, который уже был в этом запросе (эквивалентно исходному <strong><code>(binary)</code></strong>, пока для текущей паузы доступен исходный <code>FormData</code>);</li><li>записи <strong>Saved Files</strong> в <strong>Options → General</strong>;</li><li><strong>обои</strong> (фоновые медиа) из <strong>Customize</strong> — то же общее хранилище медиа, что и оформление панели.</li></ul><h3 id="автосохранение-выбранных-фаилов" tabindex="-1">Автосохранение выбранных файлов <a class="header-anchor" href="#автосохранение-выбранных-фаилов" aria-label="Permalink to &quot;Автосохранение выбранных файлов&quot;">​</a></h3><p>Параметр <strong>Auto-save new files selected via Browse</strong> (<strong>Options → General → Saved Files</strong>) управляет автосохранением файлов, выбранных в редакторе.</p><p>Если опция включена:</p><ul><li>файл копируется в <strong>Saved Files</strong>;</li><li>сохранение происходит только если ещё нет файла с той же парой <strong>имя + размер</strong>.</li></ul><p>Ограничения хранения совпадают с правилами раздела <a href="/qa-tools/docs/ru/options/customize.html">Персонализация</a>:</p><ul><li>в расширении используется <strong>IndexedDB</strong>;</li><li>в <strong>standalone</strong> действует лимит <strong>30 МБ</strong>.</li></ul><h3 id="как-данные-применяются-после-продолжения-запроса" tabindex="-1">Как данные применяются после продолжения запроса <a class="header-anchor" href="#как-данные-применяются-после-продолжения-запроса" aria-label="Permalink to &quot;Как данные применяются после продолжения запроса&quot;">​</a></h3><p>После продолжения запроса внедрённый скрипт собирает новый объект <strong><code>FormData</code></strong>:</p><ul><li>текстовые значения добавляются как обычные поля;</li><li>значения в формате <strong>data:</strong> преобразуются в файловые части;</li><li><strong><code>(binary)</code></strong> восстанавливает исходный <strong>File</strong> из сохранённого запроса, пока исходные данные ещё доступны.</li></ul><h3 id="ограничения-восстановления-фаилов" tabindex="-1">Ограничения восстановления файлов <a class="header-anchor" href="#ограничения-восстановления-фаилов" aria-label="Permalink to &quot;Ограничения восстановления файлов&quot;">​</a></h3><p>Если значение осталось в виде:</p><ul><li><strong><code>blob:</code></strong> URL;</li><li>ссылки формата <strong><code>__fileId:</code>…</strong></li></ul><p>страница не может восстановить содержимое файла самостоятельно.</p><p>В этом случае для такой части отправляется <strong>пустая заглушка</strong>, а в консоли появляется предупреждение.</p><p>Чтобы избежать этого, выберите файл заново через <strong>Browse</strong> или укажите сохранённый файл из списка.</p><h3 id="где-настраивать" tabindex="-1">Где настраивать <a class="header-anchor" href="#где-настраивать" aria-label="Permalink to &quot;Где настраивать&quot;">​</a></h3><ul><li><strong>Network</strong> — создание и изменение breakpoint на основе конкретного запроса.</li><li><strong>Options → Network → Breakpoints Requests</strong> — изменение существующего списка правил;</li></ul><h3 id="особенности-работы" tabindex="-1">Особенности работы <a class="header-anchor" href="#особенности-работы" aria-label="Permalink to &quot;Особенности работы&quot;">​</a></h3><p>При совпадении запроса с активным правилом breakpoint интерфейс автоматически переводится в режим редактирования:</p><ul><li>открывается карточка сработавшего breakpoint;</li><li>при необходимости выполняется переход во вкладку <strong>Network</strong>;</li><li>свернутый iframe инспектора автоматически разворачивается.</li></ul><p>До подтверждения или отмены выполнение запроса остаётся приостановленным.</p><h2 id="mock-response" tabindex="-1">Mock response <a class="header-anchor" href="#mock-response" aria-label="Permalink to &quot;Mock response&quot;">​</a></h2><p><img src="'+o+'" alt="Моки запросов"></p><h3 id="назначение-1" tabindex="-1">Назначение <a class="header-anchor" href="#назначение-1" aria-label="Permalink to &quot;Назначение&quot;">​</a></h3><p>Mock response полностью заменяет сетевой запрос локальным ответом.</p><p>При совпадении правила:</p><ul><li>запрос в сеть не отправляется;</li><li>создаётся синтетический ответ;</li><li>страница получает его как обычный HTTP ответ.</li></ul><h3 id="что-задается-в-mock" tabindex="-1">Что задаётся в mock <a class="header-anchor" href="#что-задается-в-mock" aria-label="Permalink to &quot;Что задаётся в mock&quot;">​</a></h3><p>Правило может содержать:</p><ul><li><strong>status</strong> и <strong>statusText</strong>;</li><li><strong>headers</strong>;</li><li><strong>body</strong>;</li><li><strong>delay</strong> перед возвратом ответа.</li></ul><h3 id="где-настраивать-1" tabindex="-1">Где настраивать <a class="header-anchor" href="#где-настраивать-1" aria-label="Permalink to &quot;Где настраивать&quot;">​</a></h3><ul><li><strong>Network</strong> — создание и изменение mock на основе конкретного запроса.</li><li><strong>Options → Network → Mocks Responses</strong> — изменение существующего списка правил;</li></ul><h3 id="особенности-работы-1" tabindex="-1">Особенности работы <a class="header-anchor" href="#особенности-работы-1" aria-label="Permalink to &quot;Особенности работы&quot;">​</a></h3><p>Если сработал mock:</p><ul><li>реальный запрос на сервер не выполняется;</li><li>breakpoint для этого вызова уже не применяется.</li></ul><p>Порядок проверки:</p><ol><li>сначала mock;</li><li>если mock не подошёл — breakpoint;</li><li>затем обычный сетевой запрос.</li></ol><p>То есть mock имеет приоритет над breakpoint.</p><hr><h2 id="сравнение-breakpoint-и-mock" tabindex="-1">Сравнение breakpoint и mock <a class="header-anchor" href="#сравнение-breakpoint-и-mock" aria-label="Permalink to &quot;Сравнение breakpoint и mock&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Механизм</th><th>Отправка в сеть</th><th>Можно изменить запрос</th><th>Можно изменить ответ</th></tr></thead><tbody><tr><td>Breakpoint</td><td>Да</td><td>Да</td><td>Нет</td></tr><tr><td>Mock response</td><td>Нет</td><td>Нет</td><td>Да</td></tr></tbody></table><hr><h2 id="ограничения" tabindex="-1">Ограничения <a class="header-anchor" href="#ограничения" aria-label="Permalink to &quot;Ограничения&quot;">​</a></h2><p>Оба механизма работают только для запросов, выполненных через:</p><ul><li><strong>fetch</strong></li><li><strong>XMLHttpRequest</strong></li></ul><p>Не перехватываются:</p><ul><li>загрузка ресурсов через <code>&lt;img&gt;</code>, <code>&lt;script&gt;</code>, <code>&lt;link&gt;</code>;</li><li>Service Worker вне текущего interception layer;</li><li>нативные сетевые вызовы браузера вне JS-контекста страницы.</li></ul><p>Запросы <strong>OPTIONS (preflight)</strong> также не участвуют в перехвате.</p><hr><h2 id="сравнение-с-charles-proxy" tabindex="-1">Сравнение с Charles Proxy <a class="header-anchor" href="#сравнение-с-charles-proxy" aria-label="Permalink to &quot;Сравнение с Charles Proxy&quot;">​</a></h2><p><strong>Charles</strong> (и аналогичные <strong>системные / внешние прокси</strong>: Fiddler, mitmproxy и др.) встаёт <strong>между клиентом и сервером</strong> на уровне ОС или отдельного приложения:</p><ul><li>видит трафик <strong>не только из браузера</strong>, но и из мобильных приложений, CLI, других программ (если направить их через прокси);</li><li>для <strong>HTTPS</strong> обычно нужна установка доверенного сертификата и <strong>SSL Proxying</strong> — расшифровка TLS на прокси;</li><li><strong>Breakpoint</strong> и <strong>Map Local / Remote</strong> применяются ко <strong>всем</strong> подходящим запросам в этом канале.</li></ul><p><strong>Vue Inspector</strong> работает <strong>внутри вкладки браузера</strong>: подменяются глобальные <strong><code>fetch</code></strong> и <strong><code>XMLHttpRequest</code></strong>.</p><table tabindex="0"><thead><tr><th>Аспект</th><th>Charles (типично)</th><th>Vue Inspector</th></tr></thead><tbody><tr><td>Уровень</td><td>Прокси / вне процесса браузера</td><td>JavaScript на странице</td></tr><tr><td>Охват</td><td>Много клиентов, весь HTTP(S) через прокси</td><td>Только этот документ: вызовы <strong>fetch</strong> и <strong>XHR</strong></td></tr><tr><td>HTTPS</td><td>Свой корень доверия, разбор TLS</td><td>Без отдельного «взлома» TLS — приложение и так отдаёт ответы в свой JS</td></tr><tr><td>Service Worker, нативные запросы</td><td>Можно перехватывать на пути</td><td>Не перехватываются этим механизмом</td></tr><tr><td>Удобство для SPA в браузере</td><td>Нужна настройка прокси и сертификатов</td><td>Включил правила в инспекторе — работает на текущем сайте</td></tr></tbody></table><p>Итог: по <strong>смыслу</strong> Breakpoint и Mock в Inspector близки к Charles (<strong>остановить / подменить ответ</strong>), но по <strong>месту действия</strong> это не сетевой прокси, а <strong>инструмент разработчика веб-страницы</strong> на том же origin-жизненном цикле, что и ваше Vue‑приложение.</p><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/ru/network/general.html">Работа с запросами</a></li><li><a href="/qa-tools/docs/ru/network/export.html">Экспорт коллекций</a></li></ul>',83)])])}const b=a(l,[["render",i]]);export{m as __pageData,b as default};
